// Insert one book
db.books.insertOne({
  title: "Dune",
  authorName: "Frank Herbert",
  publishedYear: 1965,
  price: 14.99,
  genres: ["science fiction"],
  inStock: true
})

// Result:
// { acknowledged: true, insertedId: ObjectId("...") }

db.books.insertMany([
  { title: "Foundation", authorName: "Isaac Asimov", price: 12.99 },
  { title: "Dune Messiah", authorName: "Frank Herbert", price: 13.99 }
])

// Result:
// { acknowledged: true, insertedIds: { '0': ObjectId, '1': ObjectId } }

// SELECT * FROM books;
db.books.find()

// SELECT * FROM books WHERE inStock = true;
db.books.find({ inStock: true })

// SELECT title, price FROM books WHERE inStock = true;
db.books.find(
  { inStock: true },         // filter (WHERE)
  { title: 1, price: 1 }    // projection (SELECT columns) — 1 = include, 0 = exclude
)

// SELECT * FROM books LIMIT 5;
db.books.find().limit(5)

// SELECT * FROM books ORDER BY price DESC;
db.books.find().sort({ price: -1 })   // -1 = DESC, 1 = ASC

// SELECT * FROM books ORDER BY price DESC LIMIT 5 OFFSET 10;
db.books.find().sort({ price: -1 }).skip(10).limit(5)

// SELECT * FROM books WHERE title = '1984' LIMIT 1;
db.books.findOne({ title: '1984' })

// Returns the document directly (not a cursor)
// Returns null if no match found — not an empty array

// $set  — set a field to a value (like SQL SET col = value)
db.books.updateOne(
  { title: '1984' },
  { $set: { price: 14.99, inStock: true } }
)

// $inc  — increment a numeric field
db.books.updateOne(
  { title: '1984' },
  { $inc: { price: 2 } }   // price = price + 2
)

// $unset — remove a field entirely (no SQL equivalent — closest is SET col = NULL)
db.books.updateOne(
  { title: '1984' },
  { $unset: { promoCode: '' } }
)

// $push  — add an element to an array
db.books.updateOne(
  { title: '1984' },
  { $push: { tags: 'must-read' } }
)

// $pull  — remove an element from an array
db.books.updateOne(
  { title: '1984' },
  { $pull: { tags: 'must-read' } }
)

db.books.updateOne(
  { title: 'New Book' },
  { $set: { price: 19.99 } },
  { upsert: true }   // creates the document if it doesn't exist
)
// Returns: { matchedCount: 0, modifiedCount: 0, upsertedId: ObjectId(...) }

// DELETE FROM books WHERE title = '1984';  (just the first match)
db.books.deleteOne({ title: '1984' })
// Returns: { acknowledged: true, deletedCount: 1 }

// DELETE FROM books WHERE publishedYear < 1900;
db.books.deleteMany({ publishedYear: { $lt: 1900 } })
// Returns: { acknowledged: true, deletedCount: N }

// DELETE FROM books;  (delete ALL — dangerous!)
db.books.deleteMany({})

// findOneAndDelete — get the doc before deleting it
const deleted = await db.collection('books').findOneAndDelete({ title: '1984' })
console.log(deleted)  // the deleted document is returned

// Option 1: .toArray() — load all results into memory at once
const books = await db.collection('books').find({ inStock: true }).toArray();

// Option 2: for-await-of — process one document at a time (memory-efficient)
for await (const book of db.collection('books').find({ inStock: true })) {
  console.log(book.title);
}

// findOne() is different — returns a document directly (or null), never a cursor
const book = await db.collection('books').findOne({ title: '1984' });
// book is the document object, or null if not found — NOT a cursor

// updateOne — returns stats only
const result = await db.collection('books').updateOne(
  { title: '1984' },
  { $set: { price: 15.99 } }
);
console.log(result); // { acknowledged: true, matchedCount: 1, modifiedCount: 1 }
// The actual document is NOT returned

// findOneAndUpdate — returns the document
const updatedBook = await db.collection('books').findOneAndUpdate(
  { title: '1984' },
  { $set: { price: 15.99 } },
  { returnDocument: 'after' }   // 'after' = return the updated doc, 'before' = return original
);
console.log(updatedBook.price); // 15.99

// ❌ SLOW — skip grows as pages increase
db.books.find().sort({ _id: 1 }).skip(pageNum * 20).limit(20)

// ✅ FAST — always O(1), uses the index on _id
// First page:
const page1 = await db.collection('books').find().sort({ _id: 1 }).limit(20).toArray();
const lastId = page1[page1.length - 1]._id;

// Next page: start after the last seen _id
const page2 = await db.collection('books')
  .find({ _id: { $gt: lastId } })
  .sort({ _id: 1 })
  .limit(20)
  .toArray();
